/*
 * yfs.c - Yalnix File System server
 *
 * Implements a simple Unix-style file system with:
 *   - Block cache (BLOCK_CACHESIZE=32, LRU write-back)
 *   - Inode cache (INODE_CACHESIZE=16, LRU write-back via block cache)
 *   - Free inode and free block lists (built at startup from disk scan)
 *   - Directory operations, pathname resolution, symlink support
 *   - All YFS operations: Open, Create, Read, Write, Seek, Link, Unlink,
 *     SymLink, ReadLink, MkDir, RmDir, ChDir, Stat, Sync, Shutdown
 */

#include <comp421/yalnix.h>
#include <comp421/filesystem.h>
#include <comp421/iolib.h>
#include <string.h>

/* ===== Message protocol (must match iolib.c) ===== */

struct yfs_msg {
    int type;
    int inum;
    int arg1;
    int arg2;
    int arg3;
    int arg4;
    void *ptr;
};

struct yfs_msg2 {
    int type;
    int inum;
    int arg1;
    int arg2;
    void *ptr1;
    void *ptr2;
};

#define OP_OPEN     1
#define OP_CREATE   2
#define OP_READ     3
#define OP_WRITE    4
#define OP_SEEK     5
#define OP_LINK     6
#define OP_UNLINK   7
#define OP_SYMLINK  8
#define OP_READLINK 9
#define OP_MKDIR    10
#define OP_RMDIR    11
#define OP_CHDIR    12
#define OP_STAT     13
#define OP_SYNC     14
#define OP_SHUTDOWN 15

/* ===== Constants ===== */

#define INODES_PER_BLOCK    (BLOCKSIZE / INODESIZE)
#define DIRS_PER_BLOCK      ((int)(BLOCKSIZE / sizeof(struct dir_entry)))
#define INDIRECT_PER_BLOCK  ((int)(BLOCKSIZE / sizeof(int)))

/* ===== Block cache ===== */

#define BLOCK_HASH_SIZE 64

struct block_entry {
    int blocknum;               /* disk block number; -1 if unused */
    int dirty;
    char data[BLOCKSIZE];
    struct block_entry *lru_prev, *lru_next;
    struct block_entry *hash_next;
};

static struct block_entry bcache[BLOCK_CACHESIZE];
static int bcache_used;
static struct block_entry *blru_head, *blru_tail;
static struct block_entry *bhash[BLOCK_HASH_SIZE];

/* ===== Inode cache ===== */

#define INODE_HASH_SIZE 32

struct inode_entry {
    int inum;                   /* inode number; -1 if unused */
    int dirty;
    struct inode data;
    struct inode_entry *lru_prev, *lru_next;
    struct inode_entry *hash_next;
};

static struct inode_entry icache[INODE_CACHESIZE];
static int icache_used;
static struct inode_entry *ilru_head, *ilru_tail;
static struct inode_entry *ihash[INODE_HASH_SIZE];

/* ===== File system metadata ===== */

static int g_num_blocks;
static int g_num_inodes;
static int g_first_data_block;

/* ===== Free lists ===== */

#define MAX_INODES_LIMIT 512
static int free_inodes[MAX_INODES_LIMIT];
static int nfree_inodes;
static int free_blocks[NUMBLOCKS];
static int nfree_blocks;

/* ===== Block cache operations ===== */

static void blru_remove(struct block_entry *e) {
    if (e->lru_prev) e->lru_prev->lru_next = e->lru_next;
    else blru_head = e->lru_next;
    if (e->lru_next) e->lru_next->lru_prev = e->lru_prev;
    else blru_tail = e->lru_prev;
    e->lru_prev = e->lru_next = 0;
}

static void blru_push_front(struct block_entry *e) {
    e->lru_prev = 0;
    e->lru_next = blru_head;
    if (blru_head) blru_head->lru_prev = e;
    blru_head = e;
    if (!blru_tail) blru_tail = e;
}

static void blru_touch(struct block_entry *e) {
    if (e == blru_head) return;
    blru_remove(e);
    blru_push_front(e);
}

static struct block_entry *get_block(int blocknum);

static void bhash_remove(struct block_entry *e) {
    int h = e->blocknum % BLOCK_HASH_SIZE;
    struct block_entry **pp = &bhash[h];
    while (*pp && *pp != e) pp = &(*pp)->hash_next;
    if (*pp) *pp = e->hash_next;
    e->hash_next = 0;
}

static struct block_entry *get_block(int blocknum) {
    int h = blocknum % BLOCK_HASH_SIZE;
    struct block_entry *e = bhash[h];

    /* Check cache */
    while (e) {
        if (e->blocknum == blocknum) {
            blru_touch(e);
            return e;
        }
        e = e->hash_next;
    }

    /* Get a free slot or evict LRU */
    struct block_entry *slot;
    if (bcache_used < BLOCK_CACHESIZE) {
        slot = &bcache[bcache_used++];
        slot->blocknum = -1;
        slot->dirty = 0;
        slot->lru_prev = slot->lru_next = slot->hash_next = 0;
    } else {
        /* Evict LRU tail */
        slot = blru_tail;
        if (slot->dirty) {
            WriteSector(slot->blocknum, slot->data);
            slot->dirty = 0;
        }
        bhash_remove(slot);
        blru_remove(slot);
    }

    /* Load block from disk */
    slot->blocknum = blocknum;
    slot->dirty = 0;
    ReadSector(blocknum, slot->data);

    /* Insert into hash and LRU */
    slot->hash_next = bhash[h];
    bhash[h] = slot;
    blru_push_front(slot);

    return slot;
}

/* ===== Inode cache operations ===== */

static void ilru_remove(struct inode_entry *e) {
    if (e->lru_prev) e->lru_prev->lru_next = e->lru_next;
    else ilru_head = e->lru_next;
    if (e->lru_next) e->lru_next->lru_prev = e->lru_prev;
    else ilru_tail = e->lru_prev;
    e->lru_prev = e->lru_next = 0;
}

static void ilru_push_front(struct inode_entry *e) {
    e->lru_prev = 0;
    e->lru_next = ilru_head;
    if (ilru_head) ilru_head->lru_prev = e;
    ilru_head = e;
    if (!ilru_tail) ilru_tail = e;
}

static void ilru_touch(struct inode_entry *e) {
    if (e == ilru_head) return;
    ilru_remove(e);
    ilru_push_front(e);
}

static void ihash_remove(struct inode_entry *e) {
    int h = e->inum % INODE_HASH_SIZE;
    struct inode_entry **pp = &ihash[h];
    while (*pp && *pp != e) pp = &(*pp)->hash_next;
    if (*pp) *pp = e->hash_next;
    e->hash_next = 0;
}

/*
 * Write inode back to block cache (does NOT call WriteSector directly).
 * The block cache entry is marked dirty and will be written later.
 */
static void inode_writeback(struct inode_entry *ie) {
    int inum = ie->inum;
    int blknum = 1 + (inum / INODES_PER_BLOCK);
    int offset = (inum % INODES_PER_BLOCK) * INODESIZE;
    struct block_entry *be = get_block(blknum);
    memcpy(be->data + offset, &ie->data, INODESIZE);
    be->dirty = 1;
    ie->dirty = 0;
}

static struct inode *get_inode(int inum) {
    int h = inum % INODE_HASH_SIZE;
    struct inode_entry *e = ihash[h];

    /* Check cache */
    while (e) {
        if (e->inum == inum) {
            ilru_touch(e);
            return &e->data;
        }
        e = e->hash_next;
    }

    /* Get a free slot or evict LRU */
    struct inode_entry *slot;
    if (icache_used < INODE_CACHESIZE) {
        slot = &icache[icache_used++];
        slot->inum = -1;
        slot->dirty = 0;
        slot->lru_prev = slot->lru_next = slot->hash_next = 0;
    } else {
        /* Evict LRU tail */
        slot = ilru_tail;
        if (slot->dirty) {
            inode_writeback(slot);
        }
        ihash_remove(slot);
        ilru_remove(slot);
    }

    /* Load inode from block cache */
    {
        int blknum = 1 + (inum / INODES_PER_BLOCK);
        int offset = (inum % INODES_PER_BLOCK) * INODESIZE;
        struct block_entry *be = get_block(blknum);
        memcpy(&slot->data, be->data + offset, INODESIZE);
    }
    slot->inum = inum;
    slot->dirty = 0;

    /* Insert into hash and LRU */
    slot->hash_next = ihash[h];
    ihash[h] = slot;
    ilru_push_front(slot);

    return &slot->data;
}

static void mark_inode_dirty(int inum) {
    int h = inum % INODE_HASH_SIZE;
    struct inode_entry *e = ihash[h];
    while (e) {
        if (e->inum == inum) {
            e->dirty = 1;
            return;
        }
        e = e->hash_next;
    }
}

/* ===== Cache sync ===== */

static void sync_caches(void) {
    int i;
    /* Phase 1: write all dirty inodes to block cache */
    for (i = 0; i < INODE_CACHESIZE; i++) {
        if (icache[i].inum != -1 && icache[i].dirty) {
            inode_writeback(&icache[i]);
        }
    }
    /* Phase 2: write all dirty blocks to disk */
    for (i = 0; i < BLOCK_CACHESIZE; i++) {
        if (bcache[i].blocknum != -1 && bcache[i].dirty) {
            WriteSector(bcache[i].blocknum, bcache[i].data);
            bcache[i].dirty = 0;
        }
    }
}

/* ===== Alloc/Free ===== */

static int alloc_block(void) {
    if (nfree_blocks == 0) return ERROR;
    return free_blocks[--nfree_blocks];
}

static void release_block(int blknum) {
    if (blknum <= 0 || blknum >= g_num_blocks) return;
    free_blocks[nfree_blocks++] = blknum;
    /* Also remove from cache and mark clean (invalidate) */
    int h = blknum % BLOCK_HASH_SIZE;
    struct block_entry *e = bhash[h];
    while (e) {
        if (e->blocknum == blknum) {
            e->dirty = 0; /* Don't write freed block to disk */
            break;
        }
        e = e->hash_next;
    }
}

static int alloc_inode(void) {
    if (nfree_inodes == 0) return ERROR;
    int inum = free_inodes[--nfree_inodes];
    struct inode *in = get_inode(inum);
    in->reuse++;
    mark_inode_dirty(inum);
    return inum;
}

static void release_inode(int inum) {
    struct inode *in = get_inode(inum);
    in->type = INODE_FREE;
    in->nlink = 0;
    in->size = 0;
    memset(in->direct, 0, sizeof(in->direct));
    in->indirect = 0;
    mark_inode_dirty(inum);
    free_inodes[nfree_inodes++] = inum;
}

/* ===== File block access ===== */

/*
 * Get the disk block number for a given block index in a file.
 * If create_if_missing=1, allocate a new block if needed (and mark inode dirty).
 * Returns block number (0 = hole), or ERROR on failure.
 */
static int get_file_block(int inum, int block_idx, int create_if_missing) {
    struct inode *in = get_inode(inum);

    if (block_idx < NUM_DIRECT) {
        int blknum = in->direct[block_idx];
        if (blknum == 0 && create_if_missing) {
            int newblk = alloc_block();
            if (newblk == ERROR) return ERROR;
            /* Zero-fill the new block */
            struct block_entry *be = get_block(newblk);
            memset(be->data, 0, BLOCKSIZE);
            be->dirty = 1;
            /* Re-fetch inode (get_block might have evicted it from block cache,
               but the inode cache is separate so pointer is still valid) */
            in = get_inode(inum);
            in->direct[block_idx] = newblk;
            mark_inode_dirty(inum);
            return newblk;
        }
        return blknum; /* 0 means hole */
    }

    /* Indirect block */
    int indirect_idx = block_idx - NUM_DIRECT;
    if (indirect_idx >= INDIRECT_PER_BLOCK) return ERROR; /* File too large */

    in = get_inode(inum);
    if (in->indirect == 0) {
        if (!create_if_missing) return 0; /* hole */
        int iblk = alloc_block();
        if (iblk == ERROR) return ERROR;
        /* Zero-fill indirect block */
        struct block_entry *ibe = get_block(iblk);
        memset(ibe->data, 0, BLOCKSIZE);
        ibe->dirty = 1;
        in = get_inode(inum);
        in->indirect = iblk;
        mark_inode_dirty(inum);
    }

    int indirect_blk = get_inode(inum)->indirect;
    {
        struct block_entry *ibe = get_block(indirect_blk);
        int *tbl = (int *)ibe->data;
        int blknum = tbl[indirect_idx];
        if (blknum != 0 || !create_if_missing) return blknum;
    }

    /* Allocate new data block */
    int newblk = alloc_block();
    if (newblk == ERROR) return ERROR;
    {
        struct block_entry *be = get_block(newblk);
        memset(be->data, 0, BLOCKSIZE);
        be->dirty = 1;
    }
    /* Re-fetch indirect block (get_block might have moved things around) */
    {
        struct block_entry *ibe = get_block(indirect_blk);
        ((int *)ibe->data)[indirect_idx] = newblk;
        ibe->dirty = 1;
    }
    return newblk;
}

/*
 * Free all data blocks of a file (direct and indirect).
 */
static void free_file_blocks(int inum) {
    struct inode *in = get_inode(inum);
    int i;

    /* Free direct blocks */
    for (i = 0; i < NUM_DIRECT; i++) {
        if (in->direct[i] != 0) {
            release_block(in->direct[i]);
            in->direct[i] = 0;
        }
    }
    /* Free indirect block's entries */
    if (in->indirect != 0) {
        struct block_entry *ibe = get_block(in->indirect);
        int *tbl = (int *)ibe->data;
        for (i = 0; i < INDIRECT_PER_BLOCK; i++) {
            if (tbl[i] != 0) {
                release_block(tbl[i]);
                tbl[i] = 0;
            }
        }
        ibe->dirty = 0; /* Don't need to write freed indirect block */
        release_block(in->indirect);
        in = get_inode(inum); /* Re-fetch after block ops */
        in->indirect = 0;
    }
    in = get_inode(inum);
    in->size = 0;
    memset(in->direct, 0, sizeof(in->direct));
    in->indirect = 0;
    mark_inode_dirty(inum);
}

/* ===== Directory operations ===== */

/*
 * Name comparison for directory entries.
 * dir_name: up to DIRNAMELEN bytes (not null-terminated if exactly DIRNAMELEN)
 * name: the name to search for
 * namelen: length of name (not including null terminator)
 */
static int name_match(const char *dir_name, const char *name, int namelen) {
    if (namelen > DIRNAMELEN) return 0;
    if (memcmp(dir_name, name, namelen) != 0) return 0;
    if (namelen < DIRNAMELEN && dir_name[namelen] != '\0') return 0;
    return 1;
}

/*
 * Look up a name in a directory.
 * Returns inum (>0) on success, 0 if not found, ERROR on error.
 */
static int dir_lookup(int dir_inum, const char *name, int namelen) {
    struct inode *in = get_inode(dir_inum);
    if (!in || in->type != INODE_DIRECTORY) return ERROR;

    int num_entries = in->size / (int)sizeof(struct dir_entry);
    int i;

    for (i = 0; i < num_entries; i++) {
        int byte_offset = i * (int)sizeof(struct dir_entry);
        int block_idx = byte_offset / BLOCKSIZE;
        int off_in_block = byte_offset % BLOCKSIZE;
        int blknum = get_file_block(dir_inum, block_idx, 0);
        if (blknum == 0) continue; /* hole */
        if (blknum == ERROR) return ERROR;
        struct block_entry *be = get_block(blknum);
        struct dir_entry *de = (struct dir_entry *)(be->data + off_in_block);
        if (de->inum != 0 && name_match(de->name, name, namelen)) {
            return de->inum;
        }
    }
    return 0; /* not found */
}

/*
 * Add a directory entry to dir_inum.
 * Reuses a free slot if available, otherwise appends.
 * Returns 0 on success, ERROR on failure.
 */
static int dir_add_entry(int dir_inum, const char *name, int namelen, int new_inum) {
    struct inode *in = get_inode(dir_inum);
    if (!in || in->type != INODE_DIRECTORY) return ERROR;
    if (namelen > DIRNAMELEN) return ERROR;

    int num_entries = in->size / (int)sizeof(struct dir_entry);
    int i;
    int free_slot = -1;

    /* Find a free slot */
    for (i = 0; i < num_entries; i++) {
        int byte_offset = i * (int)sizeof(struct dir_entry);
        int block_idx = byte_offset / BLOCKSIZE;
        int off_in_block = byte_offset % BLOCKSIZE;
        int blknum = get_file_block(dir_inum, block_idx, 0);
        if (blknum == 0) {
            /* Hole block - entries here are effectively free */
            if (free_slot < 0) free_slot = i;
            continue;
        }
        if (blknum == ERROR) return ERROR;
        struct block_entry *be = get_block(blknum);
        struct dir_entry *de = (struct dir_entry *)(be->data + off_in_block);
        if (de->inum == 0 && free_slot < 0) {
            free_slot = i;
        }
    }

    int target_slot = (free_slot >= 0) ? free_slot : num_entries;
    int byte_offset = target_slot * (int)sizeof(struct dir_entry);
    int block_idx = byte_offset / BLOCKSIZE;
    int off_in_block = byte_offset % BLOCKSIZE;

    int blknum = get_file_block(dir_inum, block_idx, 1);
    if (blknum == ERROR) return ERROR;

    struct block_entry *be = get_block(blknum);
    struct dir_entry *de = (struct dir_entry *)(be->data + off_in_block);
    de->inum = (short)new_inum;
    memset(de->name, 0, DIRNAMELEN);
    memcpy(de->name, name, namelen);
    be->dirty = 1;

    /* If we appended, update directory size */
    if (target_slot >= num_entries) {
        in = get_inode(dir_inum);
        in->size += (int)sizeof(struct dir_entry);
        mark_inode_dirty(dir_inum);
    }

    return 0;
}

/*
 * Remove a directory entry by name.
 * Sets inum to 0 (free slot).
 * Returns 0 on success, ERROR if not found.
 */
static int dir_remove_entry(int dir_inum, const char *name, int namelen) {
    struct inode *in = get_inode(dir_inum);
    if (!in || in->type != INODE_DIRECTORY) return ERROR;

    int num_entries = in->size / (int)sizeof(struct dir_entry);
    int i;

    for (i = 0; i < num_entries; i++) {
        int byte_offset = i * (int)sizeof(struct dir_entry);
        int block_idx = byte_offset / BLOCKSIZE;
        int off_in_block = byte_offset % BLOCKSIZE;
        int blknum = get_file_block(dir_inum, block_idx, 0);
        if (blknum == 0) continue;
        if (blknum == ERROR) return ERROR;
        struct block_entry *be = get_block(blknum);
        struct dir_entry *de = (struct dir_entry *)(be->data + off_in_block);
        if (de->inum != 0 && name_match(de->name, name, namelen)) {
            de->inum = 0;
            memset(de->name, 0, DIRNAMELEN);
            be->dirty = 1;
            return 0;
        }
    }
    return ERROR; /* not found */
}

/*
 * Check if a directory is empty (only "." and ".." entries).
 * Returns 1 if empty, 0 if not.
 */
static int dir_is_empty(int dir_inum) {
    struct inode *in = get_inode(dir_inum);
    if (!in || in->type != INODE_DIRECTORY) return 0;

    int num_entries = in->size / (int)sizeof(struct dir_entry);
    int i;

    for (i = 0; i < num_entries; i++) {
        int byte_offset = i * (int)sizeof(struct dir_entry);
        int block_idx = byte_offset / BLOCKSIZE;
        int off_in_block = byte_offset % BLOCKSIZE;
        int blknum = get_file_block(dir_inum, block_idx, 0);
        if (blknum == 0) continue;
        if (blknum == ERROR) return 0;
        struct block_entry *be = get_block(blknum);
        struct dir_entry *de = (struct dir_entry *)(be->data + off_in_block);
        if (de->inum == 0) continue;
        /* Check if it's "." or ".." */
        if (name_match(de->name, ".", 1)) continue;
        if (name_match(de->name, "..", 2)) continue;
        return 0; /* non-empty */
    }
    return 1;
}

/* ===== Symlink content reading ===== */

static int read_symlink_target(int sym_inum, char *buf, int buflen) {
    struct inode *in = get_inode(sym_inum);
    if (!in || in->type != INODE_SYMLINK) return ERROR;
    int size = in->size;
    if (size >= buflen) return ERROR;

    int i;
    int bytes_read = 0;
    for (i = 0; bytes_read < size; i++) {
        int blknum = get_file_block(sym_inum, i, 0);
        if (blknum == 0) {
            /* Hole: fill with zeros */
            int to_read = BLOCKSIZE;
            if (bytes_read + to_read > size) to_read = size - bytes_read;
            memset(buf + bytes_read, 0, to_read);
            bytes_read += to_read;
        } else if (blknum == ERROR) {
            return ERROR;
        } else {
            struct block_entry *be = get_block(blknum);
            int to_read = BLOCKSIZE;
            if (bytes_read + to_read > size) to_read = size - bytes_read;
            memcpy(buf + bytes_read, be->data, to_read);
            bytes_read += to_read;
        }
    }
    buf[size] = '\0';
    return size;
}

/* ===== Pathname resolution ===== */

/*
 * Resolve a pathname to an inode number.
 *
 * path:        the pathname to resolve
 * cwd_inum:    current directory inode number
 * follow_last: if 1, follow symlinks at the last component
 * parent_out:  if non-NULL, set to the parent directory inode number
 * last_name:   if non-NULL, filled with last component name (null-padded)
 * last_len:    if non-NULL, set to length of last component
 * symlink_depth: current symlink traversal depth
 *
 * Returns: inode number (>0), 0 if not found, ERROR on error
 */
static int resolve_path(const char *path, int cwd_inum, int follow_last,
                        int *parent_out, char *last_name, int *last_len,
                        int symlink_depth) {
    char buf[MAXPATHNAMELEN + 2];
    int pathlen;

    if (path == NULL || path[0] == '\0') return ERROR;
    if (symlink_depth > MAXSYMLINKS) return ERROR;

    pathlen = strlen(path);
    if (pathlen >= MAXPATHNAMELEN) return ERROR;

    /* Copy path to local buffer */
    memcpy(buf, path, pathlen + 1);

    /* Normalize trailing slash: treat as if "." follows */
    if (pathlen > 0 && buf[pathlen - 1] == '/') {
        if (pathlen + 1 >= MAXPATHNAMELEN) return ERROR;
        buf[pathlen] = '.';
        buf[pathlen + 1] = '\0';
        pathlen++;
    }

    /* Determine starting inode */
    int cur_inum = (buf[0] == '/') ? ROOTINODE : cwd_inum;
    char *p = buf + (buf[0] == '/' ? 1 : 0);

    /* Skip leading slashes */
    while (*p == '/') p++;

    /* If path was just "/" (now normalized to "/.") */
    if (*p == '\0') {
        /* Empty remainder means we resolved to cur_inum */
        if (parent_out) *parent_out = cur_inum;
        if (last_name) {
            last_name[0] = '.';
            if (1 < DIRNAMELEN) last_name[1] = '\0';
        }
        if (last_len) *last_len = 1;
        return cur_inum;
    }

    while (*p != '\0') {
        /* Skip slashes */
        while (*p == '/') p++;
        if (*p == '\0') break;

        /* Find end of component */
        char *end = p;
        while (*end != '/' && *end != '\0') end++;
        int clen = (int)(end - p);

        /* Determine if this is the last component */
        char *next = end;
        while (*next == '/') next++;
        int is_last = (*next == '\0');

        if (clen > DIRNAMELEN) return ERROR; /* Name too long */

        if (is_last) {
            /* Set parent and last component info */
            if (parent_out) *parent_out = cur_inum;
            if (last_name) {
                memset(last_name, 0, DIRNAMELEN + 1);
                memcpy(last_name, p, clen);
            }
            if (last_len) *last_len = clen;

            /* Look up in current directory */
            if (clen == 1 && p[0] == '.') {
                return cur_inum; /* "." = current dir */
            }
            if (clen == 2 && p[0] == '.' && p[1] == '.') {
                /* ".." = parent directory */
                return dir_lookup(cur_inum, "..", 2);
            }

            int inum = dir_lookup(cur_inum, p, clen);
            if (inum <= 0) return inum; /* 0 = not found, ERROR = error */

            if (follow_last) {
                struct inode *in = get_inode(inum);
                if (!in) return ERROR;
                if (in->type == INODE_SYMLINK) {
                    char link_buf[MAXPATHNAMELEN + 1];
                    if (read_symlink_target(inum, link_buf, sizeof(link_buf)) == ERROR)
                        return ERROR;
                    /* Relative symlink: resolve from directory where symlink is found */
                    int link_cwd = (link_buf[0] == '/') ? ROOTINODE : cur_inum;
                    return resolve_path(link_buf, link_cwd, follow_last,
                                       parent_out, last_name, last_len,
                                       symlink_depth + 1);
                }
            }
            return inum;

        } else {
            /* Non-last component: must resolve to a directory */
            if (clen == 1 && p[0] == '.') {
                /* Stay at current dir */
                p = end;
                continue;
            }
            if (clen == 2 && p[0] == '.' && p[1] == '.') {
                int parent_inum = dir_lookup(cur_inum, "..", 2);
                if (parent_inum <= 0) return parent_inum;
                cur_inum = parent_inum;
                p = end;
                continue;
            }

            int inum = dir_lookup(cur_inum, p, clen);
            if (inum == 0) return ERROR; /* Non-last component not found */
            if (inum == ERROR) return ERROR;

            /* Follow symlinks for non-last components */
            struct inode *in = get_inode(inum);
            if (!in) return ERROR;

            if (in->type == INODE_SYMLINK) {
                char link_buf[MAXPATHNAMELEN + 1];
                if (read_symlink_target(inum, link_buf, sizeof(link_buf)) == ERROR)
                    return ERROR;
                int link_cwd = (link_buf[0] == '/') ? ROOTINODE : cur_inum;
                inum = resolve_path(link_buf, link_cwd, 1, 0, 0, 0, symlink_depth + 1);
                if (inum <= 0) return inum;
                in = get_inode(inum);
                if (!in) return ERROR;
            }

            if (in->type != INODE_DIRECTORY) return ERROR;
            cur_inum = inum;
            p = end;
        }
    }

    /* Reached end without last component (shouldn't happen due to normalization) */
    if (parent_out) *parent_out = cur_inum;
    return cur_inum;
}

/* ===== Request handlers ===== */

static void reply_error(int pid) {
    struct yfs_msg rep;
    memset(&rep, 0, sizeof(rep));
    rep.inum = ERROR;
    Reply(&rep, pid);
}

static void reply_int(int pid, int val) {
    struct yfs_msg rep;
    memset(&rep, 0, sizeof(rep));
    rep.inum = val;
    Reply(&rep, pid);
}

/* ---- Open ---- */
static void handle_open(int pid, struct yfs_msg *msg) {
    char path[MAXPATHNAMELEN];
    int plen = msg->arg1;
    if (plen <= 0 || plen > MAXPATHNAMELEN) { reply_error(pid); return; }
    if (CopyFrom(pid, path, msg->ptr, plen) != 0) { reply_error(pid); return; }
    path[plen - 1] = '\0';

    int inum = resolve_path(path, msg->inum, 1, 0, 0, 0, 0);
    if (inum <= 0) { reply_error(pid); return; }

    struct inode *in = get_inode(inum);
    if (!in) { reply_error(pid); return; }

    struct yfs_msg rep;
    memset(&rep, 0, sizeof(rep));
    rep.inum = inum;
    rep.arg1 = in->reuse;
    rep.arg2 = in->type;
    Reply(&rep, pid);
}

/* ---- Create ---- */
static void handle_create(int pid, struct yfs_msg *msg) {
    char path[MAXPATHNAMELEN];
    char last_name[DIRNAMELEN + 1];
    int last_len;
    int parent_inum;
    int plen = msg->arg1;

    if (plen <= 0 || plen > MAXPATHNAMELEN) { reply_error(pid); return; }
    if (CopyFrom(pid, path, msg->ptr, plen) != 0) { reply_error(pid); return; }
    path[plen - 1] = '\0';

    if (path[0] == '\0') { reply_error(pid); return; }

    /* Resolve to find parent and last component */
    int inum = resolve_path(path, msg->inum, 0, &parent_inum, last_name, &last_len, 0);

    /* inum could be 0 (not found) or >0 (exists) or ERROR */
    if (inum == ERROR) { reply_error(pid); return; }

    /* Can't Create "." or ".." */
    if (last_len == 1 && last_name[0] == '.') { reply_error(pid); return; }
    if (last_len == 2 && last_name[0] == '.' && last_name[1] == '.') { reply_error(pid); return; }
    if (last_len == 0) { reply_error(pid); return; } /* path was just "/" */

    if (inum > 0) {
        /* File exists */
        struct inode *in = get_inode(inum);
        if (!in) { reply_error(pid); return; }
        if (in->type == INODE_DIRECTORY) { reply_error(pid); return; }
        /* Truncate: free all blocks */
        free_file_blocks(inum);
        in = get_inode(inum);
        /* Reuse count unchanged (same file) */
        struct yfs_msg rep;
        memset(&rep, 0, sizeof(rep));
        rep.inum = inum;
        rep.arg1 = in->reuse;
        rep.arg2 = INODE_REGULAR;
        Reply(&rep, pid);
        return;
    }

    /* File doesn't exist: create it */
    int new_inum = alloc_inode();
    if (new_inum == ERROR) { reply_error(pid); return; }

    /* Initialize new inode */
    struct inode *in = get_inode(new_inum);
    in->type = INODE_REGULAR;
    in->nlink = 1;
    in->size = 0;
    memset(in->direct, 0, sizeof(in->direct));
    in->indirect = 0;
    mark_inode_dirty(new_inum);

    /* Add entry to parent directory */
    if (dir_add_entry(parent_inum, last_name, last_len, new_inum) != 0) {
        release_inode(new_inum);
        reply_error(pid);
        return;
    }

    in = get_inode(new_inum);
    struct yfs_msg rep;
    memset(&rep, 0, sizeof(rep));
    rep.inum = new_inum;
    rep.arg1 = in->reuse;
    rep.arg2 = INODE_REGULAR;
    Reply(&rep, pid);
}

/* ---- Read ---- */
static void handle_read(int pid, struct yfs_msg *msg) {
    int file_inum = msg->inum;
    int reuse = msg->arg1;
    int pos = msg->arg2;
    int size = msg->arg3;

    struct inode *in = get_inode(file_inum);
    if (!in) { reply_error(pid); return; }
    if (in->type == INODE_FREE) { reply_error(pid); return; }
    if (in->reuse != reuse) { reply_error(pid); return; }
    if (size < 0) { reply_error(pid); return; }

    int file_size = in->size;
    if (pos >= file_size || size == 0) {
        reply_int(pid, 0);
        return;
    }

    int to_read = size;
    if (pos + to_read > file_size) to_read = file_size - pos;

    int bytes_done = 0;
    char *client_buf = (char *)msg->ptr;

    while (bytes_done < to_read) {
        int cur_pos = pos + bytes_done;
        int block_idx = cur_pos / BLOCKSIZE;
        int off_in_block = cur_pos % BLOCKSIZE;
        int can_read = BLOCKSIZE - off_in_block;
        if (bytes_done + can_read > to_read) can_read = to_read - bytes_done;

        int blknum = get_file_block(file_inum, block_idx, 0);
        if (blknum == ERROR) { reply_error(pid); return; }

        if (blknum == 0) {
            /* Hole: copy zeros */
            char zero_buf[BLOCKSIZE];
            memset(zero_buf, 0, can_read);
            if (CopyTo(pid, client_buf + bytes_done, zero_buf, can_read) != 0) {
                reply_error(pid); return;
            }
        } else {
            struct block_entry *be = get_block(blknum);
            if (CopyTo(pid, client_buf + bytes_done, be->data + off_in_block, can_read) != 0) {
                reply_error(pid); return;
            }
        }
        bytes_done += can_read;
    }

    reply_int(pid, bytes_done);
}

/* ---- Write ---- */
static void handle_write(int pid, struct yfs_msg *msg) {
    int file_inum = msg->inum;
    int reuse = msg->arg1;
    int pos = msg->arg2;
    int size = msg->arg3;

    struct inode *in = get_inode(file_inum);
    if (!in) { reply_error(pid); return; }
    if (in->type == INODE_FREE) { reply_error(pid); return; }
    if (in->reuse != reuse) { reply_error(pid); return; }
    if (in->type == INODE_DIRECTORY) { reply_error(pid); return; }
    if (size <= 0) { reply_int(pid, 0); return; }

    int bytes_done = 0;
    char *client_buf = (char *)msg->ptr;

    while (bytes_done < size) {
        int cur_pos = pos + bytes_done;
        int block_idx = cur_pos / BLOCKSIZE;
        int off_in_block = cur_pos % BLOCKSIZE;
        int can_write = BLOCKSIZE - off_in_block;
        if (bytes_done + can_write > size) can_write = size - bytes_done;

        int blknum = get_file_block(file_inum, block_idx, 1);
        if (blknum == ERROR) {
            /* Disk full */
            if (bytes_done == 0) { reply_error(pid); return; }
            break;
        }

        struct block_entry *be = get_block(blknum);
        if (CopyFrom(pid, be->data + off_in_block, client_buf + bytes_done, can_write) != 0) {
            reply_error(pid); return;
        }
        be->dirty = 1;
        bytes_done += can_write;

        /* Update file size if we wrote past end */
        in = get_inode(file_inum);
        if (cur_pos + can_write > in->size) {
            in->size = cur_pos + can_write;
            mark_inode_dirty(file_inum);
        }
    }

    reply_int(pid, bytes_done);
}

/* ---- Seek ---- */
static void handle_seek(int pid, struct yfs_msg *msg) {
    int file_inum = msg->inum;
    int reuse = msg->arg1;
    int cur_pos = msg->arg2;
    int whence = msg->arg3;
    int offset = msg->arg4;

    struct inode *in = get_inode(file_inum);
    if (!in) { reply_error(pid); return; }
    if (in->type == INODE_FREE) { reply_error(pid); return; }
    if (in->reuse != reuse) { reply_error(pid); return; }

    int new_pos;
    if (whence == SEEK_SET) {
        new_pos = offset;
    } else if (whence == SEEK_CUR) {
        new_pos = cur_pos + offset;
    } else if (whence == SEEK_END) {
        new_pos = in->size + offset;
    } else {
        reply_error(pid); return;
    }

    if (new_pos < 0) { reply_error(pid); return; }
    reply_int(pid, new_pos);
}

/* ---- Link ---- */
static void handle_link(int pid, struct yfs_msg2 *msg) {
    char oldpath[MAXPATHNAMELEN], newpath[MAXPATHNAMELEN];
    char last_name[DIRNAMELEN + 1];
    int last_len, parent_inum;

    int len1 = msg->arg1, len2 = msg->arg2;
    if (len1 <= 0 || len1 > MAXPATHNAMELEN || len2 <= 0 || len2 > MAXPATHNAMELEN) {
        reply_error(pid); return;
    }
    if (CopyFrom(pid, oldpath, msg->ptr1, len1) != 0) { reply_error(pid); return; }
    if (CopyFrom(pid, newpath, msg->ptr2, len2) != 0) { reply_error(pid); return; }
    oldpath[len1 - 1] = '\0';
    newpath[len2 - 1] = '\0';

    /* Resolve old path (follow symlinks) */
    int old_inum = resolve_path(oldpath, msg->inum, 1, 0, 0, 0, 0);
    if (old_inum <= 0) { reply_error(pid); return; }

    struct inode *old_in = get_inode(old_inum);
    if (!old_in || old_in->type == INODE_DIRECTORY) { reply_error(pid); return; }
    if (old_in->type == INODE_FREE) { reply_error(pid); return; }

    /* Resolve new path parent */
    int new_inum = resolve_path(newpath, msg->inum, 0, &parent_inum, last_name, &last_len, 0);
    if (new_inum != 0) { reply_error(pid); return; } /* newname must not exist */
    if (parent_inum <= 0) { reply_error(pid); return; }
    if (last_len == 0) { reply_error(pid); return; }

    /* Add entry in new directory */
    if (dir_add_entry(parent_inum, last_name, last_len, old_inum) != 0) {
        reply_error(pid); return;
    }

    /* Increment link count */
    old_in = get_inode(old_inum);
    old_in->nlink++;
    mark_inode_dirty(old_inum);

    reply_int(pid, 0);
}

/* ---- Unlink ---- */
static void handle_unlink(int pid, struct yfs_msg *msg) {
    char path[MAXPATHNAMELEN];
    char last_name[DIRNAMELEN + 1];
    int last_len, parent_inum;
    int plen = msg->arg1;

    if (plen <= 0 || plen > MAXPATHNAMELEN) { reply_error(pid); return; }
    if (CopyFrom(pid, path, msg->ptr, plen) != 0) { reply_error(pid); return; }
    path[plen - 1] = '\0';

    int inum = resolve_path(path, msg->inum, 0, &parent_inum, last_name, &last_len, 0);
    if (inum <= 0) { reply_error(pid); return; }

    /* Can't unlink "." or ".." */
    if (last_len == 1 && last_name[0] == '.') { reply_error(pid); return; }
    if (last_len == 2 && last_name[0] == '.' && last_name[1] == '.') { reply_error(pid); return; }

    struct inode *in = get_inode(inum);
    if (!in) { reply_error(pid); return; }
    if (in->type == INODE_DIRECTORY) { reply_error(pid); return; }

    /* Remove from parent directory */
    if (dir_remove_entry(parent_inum, last_name, last_len) != 0) {
        reply_error(pid); return;
    }

    /* Decrement link count */
    in = get_inode(inum);
    in->nlink--;
    if (in->nlink <= 0) {
        free_file_blocks(inum);
        release_inode(inum);
    } else {
        mark_inode_dirty(inum);
    }

    reply_int(pid, 0);
}

/* ---- SymLink ---- */
static void handle_symlink(int pid, struct yfs_msg2 *msg) {
    char oldpath[MAXPATHNAMELEN], newpath[MAXPATHNAMELEN];
    char last_name[DIRNAMELEN + 1];
    int last_len, parent_inum;

    int len1 = msg->arg1, len2 = msg->arg2;
    if (len1 <= 0 || len1 > MAXPATHNAMELEN || len2 <= 0 || len2 > MAXPATHNAMELEN) {
        reply_error(pid); return;
    }
    if (CopyFrom(pid, oldpath, msg->ptr1, len1) != 0) { reply_error(pid); return; }
    if (CopyFrom(pid, newpath, msg->ptr2, len2) != 0) { reply_error(pid); return; }
    oldpath[len1 - 1] = '\0';
    newpath[len2 - 1] = '\0';

    if (oldpath[0] == '\0') { reply_error(pid); return; }
    if (newpath[0] == '\0') { reply_error(pid); return; }

    /* Resolve new path's parent (don't follow last symlink) */
    int new_inum = resolve_path(newpath, msg->inum, 0, &parent_inum, last_name, &last_len, 0);
    if (new_inum != 0) { reply_error(pid); return; } /* newname must not exist */
    if (parent_inum <= 0) { reply_error(pid); return; }
    if (last_len == 0) { reply_error(pid); return; }

    /* Allocate inode for symlink */
    int sym_inum = alloc_inode();
    if (sym_inum == ERROR) { reply_error(pid); return; }

    /* Initialize symlink inode */
    struct inode *in = get_inode(sym_inum);
    in->type = INODE_SYMLINK;
    in->nlink = 1;
    in->size = 0;
    memset(in->direct, 0, sizeof(in->direct));
    in->indirect = 0;
    mark_inode_dirty(sym_inum);

    /* Write target path to symlink's data */
    int target_len = strlen(oldpath); /* NOT including null terminator */
    int written = 0;
    while (written < target_len) {
        int block_idx = written / BLOCKSIZE;
        int off_in_block = written % BLOCKSIZE;
        int blknum = get_file_block(sym_inum, block_idx, 1);
        if (blknum == ERROR) {
            release_inode(sym_inum);
            reply_error(pid); return;
        }
        int can_write = BLOCKSIZE - off_in_block;
        if (written + can_write > target_len) can_write = target_len - written;
        struct block_entry *be = get_block(blknum);
        memcpy(be->data + off_in_block, oldpath + written, can_write);
        be->dirty = 1;
        written += can_write;
    }
    in = get_inode(sym_inum);
    in->size = target_len;
    mark_inode_dirty(sym_inum);

    /* Add entry in parent directory */
    if (dir_add_entry(parent_inum, last_name, last_len, sym_inum) != 0) {
        free_file_blocks(sym_inum);
        release_inode(sym_inum);
        reply_error(pid); return;
    }

    reply_int(pid, 0);
}

/* ---- ReadLink ---- */
static void handle_readlink(int pid, struct yfs_msg2 *msg) {
    char path[MAXPATHNAMELEN];
    int plen = msg->arg1;
    int buflen = msg->arg2;

    if (plen <= 0 || plen > MAXPATHNAMELEN) { reply_error(pid); return; }
    if (CopyFrom(pid, path, msg->ptr1, plen) != 0) { reply_error(pid); return; }
    path[plen - 1] = '\0';

    /* Resolve path WITHOUT following last symlink */
    int inum = resolve_path(path, msg->inum, 0, 0, 0, 0, 0);
    if (inum <= 0) { reply_error(pid); return; }

    struct inode *in = get_inode(inum);
    if (!in || in->type != INODE_SYMLINK) { reply_error(pid); return; }

    int sym_size = in->size;
    int to_copy = (sym_size < buflen) ? sym_size : buflen;

    /* Copy symlink content to client's buffer */
    int bytes_done = 0;
    char *client_buf = (char *)msg->ptr2;

    while (bytes_done < to_copy) {
        int block_idx = bytes_done / BLOCKSIZE;
        int off_in_block = bytes_done % BLOCKSIZE;
        int can_read = BLOCKSIZE - off_in_block;
        if (bytes_done + can_read > to_copy) can_read = to_copy - bytes_done;

        int blknum = get_file_block(inum, block_idx, 0);
        if (blknum == ERROR) { reply_error(pid); return; }

        if (blknum == 0) {
            char zeros[BLOCKSIZE];
            memset(zeros, 0, can_read);
            if (CopyTo(pid, client_buf + bytes_done, zeros, can_read) != 0) {
                reply_error(pid); return;
            }
        } else {
            struct block_entry *be = get_block(blknum);
            if (CopyTo(pid, client_buf + bytes_done, be->data + off_in_block, can_read) != 0) {
                reply_error(pid); return;
            }
        }
        bytes_done += can_read;
    }

    reply_int(pid, to_copy);
}

/* ---- MkDir ---- */
static void handle_mkdir(int pid, struct yfs_msg *msg) {
    char path[MAXPATHNAMELEN];
    char last_name[DIRNAMELEN + 1];
    int last_len, parent_inum;
    int plen = msg->arg1;

    if (plen <= 0 || plen > MAXPATHNAMELEN) { reply_error(pid); return; }
    if (CopyFrom(pid, path, msg->ptr, plen) != 0) { reply_error(pid); return; }
    path[plen - 1] = '\0';

    int inum = resolve_path(path, msg->inum, 0, &parent_inum, last_name, &last_len, 0);
    if (inum != 0) { reply_error(pid); return; } /* Already exists */
    if (parent_inum <= 0) { reply_error(pid); return; }
    if (last_len == 0) { reply_error(pid); return; }
    /* Can't create "." or ".." as new dir */
    if (last_len == 1 && last_name[0] == '.') { reply_error(pid); return; }
    if (last_len == 2 && last_name[0] == '.' && last_name[1] == '.') { reply_error(pid); return; }

    /* Allocate new directory inode */
    int new_inum = alloc_inode();
    if (new_inum == ERROR) { reply_error(pid); return; }

    struct inode *in = get_inode(new_inum);
    in->type = INODE_DIRECTORY;
    in->nlink = 2; /* "." and parent's entry */
    in->size = 0;
    memset(in->direct, 0, sizeof(in->direct));
    in->indirect = 0;
    mark_inode_dirty(new_inum);

    /* Add "." entry (points to itself) */
    if (dir_add_entry(new_inum, ".", 1, new_inum) != 0) {
        release_inode(new_inum);
        reply_error(pid); return;
    }

    /* Add ".." entry (points to parent) */
    if (dir_add_entry(new_inum, "..", 2, parent_inum) != 0) {
        free_file_blocks(new_inum);
        release_inode(new_inum);
        reply_error(pid); return;
    }

    /* Add entry in parent directory */
    if (dir_add_entry(parent_inum, last_name, last_len, new_inum) != 0) {
        free_file_blocks(new_inum);
        release_inode(new_inum);
        reply_error(pid); return;
    }

    /* Increment parent's nlink (because new dir's ".." points to it) */
    struct inode *par_in = get_inode(parent_inum);
    par_in->nlink++;
    mark_inode_dirty(parent_inum);

    reply_int(pid, 0);
}

/* ---- RmDir ---- */
static void handle_rmdir(int pid, struct yfs_msg *msg) {
    char path[MAXPATHNAMELEN];
    char last_name[DIRNAMELEN + 1];
    int last_len, parent_inum;
    int plen = msg->arg1;

    if (plen <= 0 || plen > MAXPATHNAMELEN) { reply_error(pid); return; }
    if (CopyFrom(pid, path, msg->ptr, plen) != 0) { reply_error(pid); return; }
    path[plen - 1] = '\0';

    int inum = resolve_path(path, msg->inum, 0, &parent_inum, last_name, &last_len, 0);
    if (inum <= 0) { reply_error(pid); return; }

    /* Can't remove "." or ".." or root */
    if (last_len == 1 && last_name[0] == '.') { reply_error(pid); return; }
    if (last_len == 2 && last_name[0] == '.' && last_name[1] == '.') { reply_error(pid); return; }
    if (inum == ROOTINODE) { reply_error(pid); return; }

    struct inode *in = get_inode(inum);
    if (!in || in->type != INODE_DIRECTORY) { reply_error(pid); return; }

    /* Directory must be empty */
    if (!dir_is_empty(inum)) { reply_error(pid); return; }

    /* Remove from parent */
    if (dir_remove_entry(parent_inum, last_name, last_len) != 0) {
        reply_error(pid); return;
    }

    /* Decrement parent's nlink (because removed dir's ".." pointed to it) */
    struct inode *par_in = get_inode(parent_inum);
    par_in->nlink--;
    mark_inode_dirty(parent_inum);

    /* Free directory's blocks and inode */
    free_file_blocks(inum);
    release_inode(inum);

    reply_int(pid, 0);
}

/* ---- ChDir ---- */
static void handle_chdir(int pid, struct yfs_msg *msg) {
    char path[MAXPATHNAMELEN];
    int plen = msg->arg1;

    if (plen <= 0 || plen > MAXPATHNAMELEN) { reply_error(pid); return; }
    if (CopyFrom(pid, path, msg->ptr, plen) != 0) { reply_error(pid); return; }
    path[plen - 1] = '\0';

    int inum = resolve_path(path, msg->inum, 1, 0, 0, 0, 0);
    if (inum <= 0) { reply_error(pid); return; }

    struct inode *in = get_inode(inum);
    if (!in || in->type != INODE_DIRECTORY) { reply_error(pid); return; }

    /* Return the new directory inode number */
    reply_int(pid, inum);
}

/* ---- Stat ---- */
static void handle_stat(int pid, struct yfs_msg2 *msg) {
    char path[MAXPATHNAMELEN];
    int plen = msg->arg1;

    if (plen <= 0 || plen > MAXPATHNAMELEN) { reply_error(pid); return; }
    if (CopyFrom(pid, path, msg->ptr1, plen) != 0) { reply_error(pid); return; }
    path[plen - 1] = '\0';

    /* Stat follows symlinks at last component */
    int inum = resolve_path(path, msg->inum, 1, 0, 0, 0, 0);
    if (inum <= 0) { reply_error(pid); return; }

    struct inode *in = get_inode(inum);
    if (!in || in->type == INODE_FREE) { reply_error(pid); return; }

    struct Stat sb;
    sb.inum = inum;
    sb.type = in->type;
    sb.size = in->size;
    sb.nlink = in->nlink;

    /* Copy Stat struct to client's statbuf */
    if (CopyTo(pid, msg->ptr2, &sb, sizeof(sb)) != 0) { reply_error(pid); return; }

    reply_int(pid, 0);
}

/* ---- Sync ---- */
static void handle_sync(int pid) {
    sync_caches();
    reply_int(pid, 0);
}

/* ---- Shutdown ---- */
static void handle_shutdown(int pid) {
    sync_caches();
    TracePrintf(0, "YFS: Shutting down\n");
    reply_int(pid, 0);
    Exit(0);
}

/* ===== Initialization ===== */

static void init_fs(void) {
    int i;
    char super_buf[BLOCKSIZE];

    /* Initialize block cache */
    bcache_used = 0;
    blru_head = blru_tail = 0;
    memset(bhash, 0, sizeof(bhash));
    for (i = 0; i < BLOCK_CACHESIZE; i++) {
        bcache[i].blocknum = -1;
        bcache[i].dirty = 0;
        bcache[i].lru_prev = bcache[i].lru_next = bcache[i].hash_next = 0;
    }

    /* Initialize inode cache */
    icache_used = 0;
    ilru_head = ilru_tail = 0;
    memset(ihash, 0, sizeof(ihash));
    for (i = 0; i < INODE_CACHESIZE; i++) {
        icache[i].inum = -1;
        icache[i].dirty = 0;
        icache[i].lru_prev = icache[i].lru_next = icache[i].hash_next = 0;
    }

    /* Read superblock directly (bypass cache for initial read) */
    ReadSector(1, super_buf);
    struct fs_header *hdr = (struct fs_header *)super_buf;
    g_num_blocks = hdr->num_blocks;
    g_num_inodes = hdr->num_inodes;
    g_first_data_block = 1 + (g_num_inodes + 1 + INODES_PER_BLOCK - 1) / INODES_PER_BLOCK;

    TracePrintf(0, "YFS init: num_blocks=%d, num_inodes=%d, first_data=%d\n",
                g_num_blocks, g_num_inodes, g_first_data_block);

    /* Track which data blocks are in use */
    static int block_used[NUMBLOCKS];
    memset(block_used, 0, sizeof(block_used));
    /* Mark boot/inode blocks as used */
    for (i = 0; i < g_first_data_block; i++) block_used[i] = 1;

    /* Scan all inodes to build free lists */
    nfree_inodes = 0;
    for (i = 1; i <= g_num_inodes; i++) {
        struct inode *in = get_inode(i);
        if (in->type == INODE_FREE) {
            free_inodes[nfree_inodes++] = i;
        } else {
            int j;
            for (j = 0; j < NUM_DIRECT; j++) {
                if (in->direct[j] != 0 && in->direct[j] < g_num_blocks)
                    block_used[in->direct[j]] = 1;
            }
            if (in->indirect != 0 && in->indirect < g_num_blocks) {
                block_used[in->indirect] = 1;
                struct block_entry *ibe = get_block(in->indirect);
                int *tbl = (int *)ibe->data;
                int k;
                for (k = 0; k < INDIRECT_PER_BLOCK; k++) {
                    if (tbl[k] != 0 && tbl[k] < g_num_blocks)
                        block_used[tbl[k]] = 1;
                }
            }
        }
    }

    /* Build free block stack */
    nfree_blocks = 0;
    for (i = g_first_data_block; i < g_num_blocks; i++) {
        if (!block_used[i]) free_blocks[nfree_blocks++] = i;
    }

    TracePrintf(0, "YFS: %d free blocks, %d free inodes\n", nfree_blocks, nfree_inodes);
}

/* ===== Main ===== */

int main(int argc, char **argv) {
    /* Register as file server */
    if (Register(FILE_SERVER) != 0) {
        TracePrintf(0, "YFS: Register failed\n");
        Exit(1);
    }

    /* Initialize the file system */
    init_fs();

    /* Fork and exec first client process */
    if (argc > 1) {
        int pid = Fork();
        if (pid == 0) {
            Exec(argv[1], argv + 1);
        }
    }

    /* Main server loop */
    struct yfs_msg msg;
    while (1) {
        int sender_pid = Receive(&msg);

        if (sender_pid == 0) {
            /* Deadlock break: no more clients */
            sync_caches();
            Exit(0);
        }
        if (sender_pid == ERROR) continue;

        switch (msg.type) {
            case OP_OPEN:
                handle_open(sender_pid, &msg);
                break;
            case OP_CREATE:
                handle_create(sender_pid, &msg);
                break;
            case OP_READ:
                handle_read(sender_pid, &msg);
                break;
            case OP_WRITE:
                handle_write(sender_pid, &msg);
                break;
            case OP_SEEK:
                handle_seek(sender_pid, &msg);
                break;
            case OP_LINK:
                handle_link(sender_pid, (struct yfs_msg2 *)&msg);
                break;
            case OP_UNLINK:
                handle_unlink(sender_pid, &msg);
                break;
            case OP_SYMLINK:
                handle_symlink(sender_pid, (struct yfs_msg2 *)&msg);
                break;
            case OP_READLINK:
                handle_readlink(sender_pid, (struct yfs_msg2 *)&msg);
                break;
            case OP_MKDIR:
                handle_mkdir(sender_pid, &msg);
                break;
            case OP_RMDIR:
                handle_rmdir(sender_pid, &msg);
                break;
            case OP_CHDIR:
                handle_chdir(sender_pid, &msg);
                break;
            case OP_STAT:
                handle_stat(sender_pid, (struct yfs_msg2 *)&msg);
                break;
            case OP_SYNC:
                handle_sync(sender_pid);
                break;
            case OP_SHUTDOWN:
                handle_shutdown(sender_pid);
                break;
            default:
                TracePrintf(0, "YFS: Unknown op %d\n", msg.type);
                reply_error(sender_pid);
                break;
        }
    }

    return 0;
}

/*
 * iolib.c - YFS client library
 *
 * Provides stub functions that communicate with the YFS server via IPC.
 * Each process has its own fd table and current working directory inode.
 */

#include <comp421/yalnix.h>
#include <comp421/iolib.h>
#include <comp421/filesystem.h>
#include <string.h>

/* ===== Message protocol ===== */

/*
 * One-pointer message: 4+4+4+4+4+4+8 = 32 bytes
 * Used for: Open, Create, Read, Write, Seek, Unlink, MkDir, RmDir, ChDir, Sync, Shutdown
 */
struct yfs_msg {
    int type;   /* operation type */
    int inum;   /* cwd_inum (path ops) or file_inum (fd ops) */
    int arg1;   /* pathlen, reuse, or 0 */
    int arg2;   /* pos or 0 */
    int arg3;   /* size, whence, or 0 */
    int arg4;   /* offset or 0 */
    void *ptr;  /* pathname or data buffer */
};

/*
 * Two-pointer message: 4+4+4+4+8+8 = 32 bytes
 * Used for: Link, SymLink, ReadLink, Stat
 */
struct yfs_msg2 {
    int type;   /* operation type */
    int inum;   /* cwd_inum */
    int arg1;   /* len1 (first path length) */
    int arg2;   /* len2 (second path / buf length) */
    void *ptr1; /* first path */
    void *ptr2; /* second path or result buffer */
};

/* Operation type codes */
#define OP_OPEN     1
#define OP_CREATE   2
#define OP_READ     3
#define OP_WRITE    4
#define OP_SEEK     5
#define OP_LINK     6
#define OP_UNLINK   7
#define OP_SYMLINK  8
#define OP_READLINK 9
#define OP_MKDIR    10
#define OP_RMDIR    11
#define OP_CHDIR    12
#define OP_STAT     13
#define OP_SYNC     14
#define OP_SHUTDOWN 15

/* ===== File descriptor table ===== */

struct fd_entry {
    int used;
    int inum;
    int reuse;
    int pos;
    int is_dir; /* 1 if directory (write not allowed) */
};

static struct fd_entry fd_table[MAX_OPEN_FILES];
static int cwd_inum = ROOTINODE;

/* Find lowest available fd slot */
static int find_free_fd(void) {
    int i;
    for (i = 0; i < MAX_OPEN_FILES; i++) {
        if (!fd_table[i].used) return i;
    }
    return ERROR;
}

/* Validate fd and return entry pointer */
static struct fd_entry *get_fd(int fd) {
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].used) return (void *)0;
    return &fd_table[fd];
}

/* ===== Library functions ===== */

int Open(char *pathname) {
    struct yfs_msg msg;
    int fd, plen;

    if (pathname == NULL || pathname[0] == '\0') return ERROR;
    plen = strlen(pathname) + 1;
    if (plen > MAXPATHNAMELEN) return ERROR;

    fd = find_free_fd();
    if (fd == ERROR) return ERROR;

    msg.type = OP_OPEN;
    msg.inum = cwd_inum;
    msg.arg1 = plen;
    msg.arg2 = 0;
    msg.arg3 = 0;
    msg.arg4 = 0;
    msg.ptr = pathname;

    Send(&msg, -FILE_SERVER);
    /* Reply: inum=file_inum (or ERROR), arg1=reuse, arg2=inode_type */
    if (msg.inum == ERROR) return ERROR;

    fd_table[fd].used = 1;
    fd_table[fd].inum = msg.inum;
    fd_table[fd].reuse = msg.arg1;
    fd_table[fd].pos = 0;
    fd_table[fd].is_dir = (msg.arg2 == INODE_DIRECTORY);
    return fd;
}

int Create(char *pathname) {
    struct yfs_msg msg;
    int fd, plen;

    if (pathname == NULL || pathname[0] == '\0') return ERROR;
    plen = strlen(pathname) + 1;
    if (plen > MAXPATHNAMELEN) return ERROR;

    fd = find_free_fd();
    if (fd == ERROR) return ERROR;

    msg.type = OP_CREATE;
    msg.inum = cwd_inum;
    msg.arg1 = plen;
    msg.arg2 = 0;
    msg.arg3 = 0;
    msg.arg4 = 0;
    msg.ptr = pathname;

    Send(&msg, -FILE_SERVER);
    /* Reply: inum=file_inum (or ERROR), arg1=reuse, arg2=inode_type */
    if (msg.inum == ERROR) return ERROR;

    fd_table[fd].used = 1;
    fd_table[fd].inum = msg.inum;
    fd_table[fd].reuse = msg.arg1;
    fd_table[fd].pos = 0;
    fd_table[fd].is_dir = 0; /* Create always creates regular files */
    return fd;
}

int Close(int fd) {
    struct fd_entry *entry = get_fd(fd);
    if (!entry) return ERROR;
    entry->used = 0;
    return 0;
}

int Read(int fd, void *buf, int size) {
    struct yfs_msg msg;
    struct fd_entry *entry;

    entry = get_fd(fd);
    if (!entry) return ERROR;
    if (buf == NULL || size < 0) return ERROR;
    if (size == 0) return 0;

    msg.type = OP_READ;
    msg.inum = entry->inum;
    msg.arg1 = entry->reuse;
    msg.arg2 = entry->pos;
    msg.arg3 = size;
    msg.arg4 = 0;
    msg.ptr = buf;

    Send(&msg, -FILE_SERVER);
    /* Reply: inum=bytes_read (or ERROR) */
    if (msg.inum == ERROR) return ERROR;
    entry->pos += msg.inum;
    return msg.inum;
}

int Write(int fd, void *buf, int size) {
    struct yfs_msg msg;
    struct fd_entry *entry;

    entry = get_fd(fd);
    if (!entry) return ERROR;
    if (entry->is_dir) return ERROR; /* Can't write to directory */
    if (buf == NULL || size < 0) return ERROR;
    if (size == 0) return 0;

    msg.type = OP_WRITE;
    msg.inum = entry->inum;
    msg.arg1 = entry->reuse;
    msg.arg2 = entry->pos;
    msg.arg3 = size;
    msg.arg4 = 0;
    msg.ptr = buf;

    Send(&msg, -FILE_SERVER);
    /* Reply: inum=bytes_written (or ERROR) */
    if (msg.inum == ERROR) return ERROR;
    entry->pos += msg.inum;
    return msg.inum;
}

int Seek(int fd, int offset, int whence) {
    struct yfs_msg msg;
    struct fd_entry *entry;

    entry = get_fd(fd);
    if (!entry) return ERROR;

    msg.type = OP_SEEK;
    msg.inum = entry->inum;
    msg.arg1 = entry->reuse;
    msg.arg2 = entry->pos;
    msg.arg3 = whence;
    msg.arg4 = offset;
    msg.ptr = (void *)0;

    Send(&msg, -FILE_SERVER);
    /* Reply: inum=new_pos (or ERROR) */
    if (msg.inum == ERROR) return ERROR;
    entry->pos = msg.inum;
    return msg.inum;
}

int Link(char *oldname, char *newname) {
    struct yfs_msg2 msg;
    int len1, len2;

    if (oldname == NULL || oldname[0] == '\0') return ERROR;
    if (newname == NULL || newname[0] == '\0') return ERROR;
    len1 = strlen(oldname) + 1;
    len2 = strlen(newname) + 1;
    if (len1 > MAXPATHNAMELEN || len2 > MAXPATHNAMELEN) return ERROR;

    msg.type = OP_LINK;
    msg.inum = cwd_inum;
    msg.arg1 = len1;
    msg.arg2 = len2;
    msg.ptr1 = oldname;
    msg.ptr2 = newname;

    Send(&msg, -FILE_SERVER);
    return ((struct yfs_msg *)&msg)->inum; /* 0 or ERROR */
}

int Unlink(char *pathname) {
    struct yfs_msg msg;
    int plen;

    if (pathname == NULL || pathname[0] == '\0') return ERROR;
    plen = strlen(pathname) + 1;
    if (plen > MAXPATHNAMELEN) return ERROR;

    msg.type = OP_UNLINK;
    msg.inum = cwd_inum;
    msg.arg1 = plen;
    msg.arg2 = 0;
    msg.arg3 = 0;
    msg.arg4 = 0;
    msg.ptr = pathname;

    Send(&msg, -FILE_SERVER);
    return msg.inum; /* 0 or ERROR */
}

int SymLink(char *oldname, char *newname) {
    struct yfs_msg2 msg;
    int len1, len2;

    if (oldname == NULL || oldname[0] == '\0') return ERROR;
    if (newname == NULL || newname[0] == '\0') return ERROR;
    len1 = strlen(oldname) + 1;
    len2 = strlen(newname) + 1;
    if (len1 > MAXPATHNAMELEN || len2 > MAXPATHNAMELEN) return ERROR;

    msg.type = OP_SYMLINK;
    msg.inum = cwd_inum;
    msg.arg1 = len1;
    msg.arg2 = len2;
    msg.ptr1 = oldname;
    msg.ptr2 = newname;

    Send(&msg, -FILE_SERVER);
    return ((struct yfs_msg *)&msg)->inum; /* 0 or ERROR */
}

int ReadLink(char *pathname, char *buf, int len) {
    struct yfs_msg2 msg;
    int plen;

    if (pathname == NULL || pathname[0] == '\0') return ERROR;
    if (buf == NULL || len <= 0) return ERROR;
    plen = strlen(pathname) + 1;
    if (plen > MAXPATHNAMELEN) return ERROR;

    msg.type = OP_READLINK;
    msg.inum = cwd_inum;
    msg.arg1 = plen;
    msg.arg2 = len;
    msg.ptr1 = pathname;
    msg.ptr2 = buf;

    Send(&msg, -FILE_SERVER);
    return ((struct yfs_msg *)&msg)->inum; /* bytes_read or ERROR */
}

int MkDir(char *pathname) {
    struct yfs_msg msg;
    int plen;

    if (pathname == NULL || pathname[0] == '\0') return ERROR;
    plen = strlen(pathname) + 1;
    if (plen > MAXPATHNAMELEN) return ERROR;

    msg.type = OP_MKDIR;
    msg.inum = cwd_inum;
    msg.arg1 = plen;
    msg.arg2 = 0;
    msg.arg3 = 0;
    msg.arg4 = 0;
    msg.ptr = pathname;

    Send(&msg, -FILE_SERVER);
    return msg.inum; /* 0 or ERROR */
}

int RmDir(char *pathname) {
    struct yfs_msg msg;
    int plen;

    if (pathname == NULL || pathname[0] == '\0') return ERROR;
    plen = strlen(pathname) + 1;
    if (plen > MAXPATHNAMELEN) return ERROR;

    msg.type = OP_RMDIR;
    msg.inum = cwd_inum;
    msg.arg1 = plen;
    msg.arg2 = 0;
    msg.arg3 = 0;
    msg.arg4 = 0;
    msg.ptr = pathname;

    Send(&msg, -FILE_SERVER);
    return msg.inum; /* 0 or ERROR */
}

int ChDir(char *pathname) {
    struct yfs_msg msg;
    int plen;

    if (pathname == NULL || pathname[0] == '\0') return ERROR;
    plen = strlen(pathname) + 1;
    if (plen > MAXPATHNAMELEN) return ERROR;

    msg.type = OP_CHDIR;
    msg.inum = cwd_inum;
    msg.arg1 = plen;
    msg.arg2 = 0;
    msg.arg3 = 0;
    msg.arg4 = 0;
    msg.ptr = pathname;

    Send(&msg, -FILE_SERVER);
    /* Reply: inum=new_cwd_inum (or ERROR) */
    if (msg.inum == ERROR) return ERROR;
    cwd_inum = msg.inum;
    return 0;
}

int Stat(char *pathname, struct Stat *statbuf) {
    struct yfs_msg2 msg;
    int plen;

    if (pathname == NULL || pathname[0] == '\0') return ERROR;
    if (statbuf == NULL) return ERROR;
    plen = strlen(pathname) + 1;
    if (plen > MAXPATHNAMELEN) return ERROR;

    msg.type = OP_STAT;
    msg.inum = cwd_inum;
    msg.arg1 = plen;
    msg.arg2 = 0;
    msg.ptr1 = pathname;
    msg.ptr2 = statbuf;

    Send(&msg, -FILE_SERVER);
    return ((struct yfs_msg *)&msg)->inum; /* 0 or ERROR */
}

int Sync(void) {
    struct yfs_msg msg;
    msg.type = OP_SYNC;
    msg.inum = 0;
    msg.arg1 = 0;
    msg.arg2 = 0;
    msg.arg3 = 0;
    msg.arg4 = 0;
    msg.ptr = (void *)0;
    Send(&msg, -FILE_SERVER);
    return 0;
}

int Shutdown(void) {
    struct yfs_msg msg;
    msg.type = OP_SHUTDOWN;
    msg.inum = 0;
    msg.arg1 = 0;
    msg.arg2 = 0;
    msg.arg3 = 0;
    msg.arg4 = 0;
    msg.ptr = (void *)0;
    Send(&msg, -FILE_SERVER);
    return 0;
}

